import{_ as i,r,o as l,c as t,a,b as n,d as o,e as d}from"./app-7b6a7290.js";const p={},u={href:"https://zhuanlan.zhihu.com/p/2048317502342666078",target:"_blank",rel:"noopener noreferrer"};function c(h,e){const s=r("ExternalLinkIcon");return l(),t("div",null,[e[1]||(e[1]=a("h1",{id:"loop-engineering",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#loop-engineering","aria-hidden":"true"},"#"),n(" Loop Engineering")],-1)),e[2]||(e[2]=a("p",null,"循环工程",-1)),e[3]||(e[3]=a("p",null,"循环工程是指你不再是发出指令的人，而是设计一个能够执行指令的系统。",-1)),e[4]||(e[4]=a("p",null,"对于使用 Grok、Claude Code、Codex、Cursor 和其他 AI 编码代理的开发者而言，循环是一种递归目标：您定义一个目标，AI 会迭代执行（通常会使用子代理、验证和外部状态），直到目标完成或循环决定将任务交还给您。",-1)),a("p",null,[a("a",u,[e[0]||(e[0]=n("Loop Engineering 深度解析与实战指南",-1)),o(s)])]),e[5]||(e[5]=d(`<ul><li>Discover (发现)</li><li>Plan (计划)</li><li>Execute (执行)</li><li>Verify (验证)</li><li>Iterate (迭代)</li></ul><p>我认为 Loop Engineering 最核心的思想哲学是：不要信任模型的上下文窗口作为持久化存储。模型会遗忘，会漂移，会压缩信息导致约束丢失。</p><p>企业级AI开发的最佳实践是：所有状态都存储在外部系统中——git 仓库、markdown 文件、数据库、issue 跟踪系统等。每个循环迭代都从一个全新的上下文窗口开始，但需要在实际持久化的内容基础上进行工作。</p><p>这就是为什么最原始的 Ralph Loop 这么有影响力，只用了一行 bash 代码，就让AI永无止境的帮你干活：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>while :; do cat PROMPT.md | claude-code; done
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="六大要素" tabindex="-1"><a class="header-anchor" href="#六大要素" aria-hidden="true">#</a> 六大要素</h2><h3 id="_1-automations-自动化" tabindex="-1"><a class="header-anchor" href="#_1-automations-自动化" aria-hidden="true">#</a> 1.Automations (自动化)</h3><p>自动化是将一次性 AI 运行转变为真正循环的关键。它允许我们指定任务何时运行、运行频率以及在什么环境下运行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 每天早上6点运行，处理CI失败</span>
/loop <span class="token string">&quot;Run the triage skill on yesterday&#39;s CI failures and open PRs for fixes&quot;</span> <span class="token parameter variable">--schedule</span> <span class="token string">&quot;0 6 * * *&quot;</span>
<span class="token comment"># 运行直到所有测试通过</span>
/goal all tests <span class="token keyword">in</span> test/auth pass and the lint step is clean
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-worktrees-工作树-无冲突协作并行" tabindex="-1"><a class="header-anchor" href="#_2-worktrees-工作树-无冲突协作并行" aria-hidden="true">#</a> 2. Worktrees (工作树)：无冲突协作并行</h3><p>当我们同时运行多个 AI 时，需要考虑最多的问题就是文件冲突。Git 工作树为每个 AI Agent 提供了一个独立的工作目录，共享相同的仓库历史但不共享文件。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在独立的工作树中打开一个会话</span>
claude-code <span class="token parameter variable">--worktree</span> feature/add-search
<span class="token comment"># 子代理自动使用独立工作树</span>
/subagent <span class="token string">&quot;Build the search API&quot;</span> <span class="token parameter variable">--isolation</span> worktree
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-skills-技能" tabindex="-1"><a class="header-anchor" href="#_3-skills-技能" aria-hidden="true">#</a> 3. Skills (技能)</h3><h3 id="_4-connectors-连接器" tabindex="-1"><a class="header-anchor" href="#_4-connectors-连接器" aria-hidden="true">#</a> 4. Connectors(连接器)</h3><p>连接器(基于MCP协议)主要作用是让循环能够与我们已在使用的工具进行交互。它是&quot;AI告诉你该做什么事情&quot;和&quot;AI实际帮你完成了哪些事情&quot;之间的关键区别</p><h3 id="_5-subagent-子代理" tabindex="-1"><a class="header-anchor" href="#_5-subagent-子代理" aria-hidden="true">#</a> 5. Subagent(子代理)</h3><p>最高效的循环设计原则是：一个代理负责实现，另一个代理负责验证。</p><h3 id="_6-state-状态-loop范式的记忆保障" tabindex="-1"><a class="header-anchor" href="#_6-state-状态-loop范式的记忆保障" aria-hidden="true">#</a> 6. State (状态)：Loop范式的记忆保障</h3><p>模型会遗忘，但仓库不会。</p><p>常见的状态存储方式有：</p><ul><li>Markdown 文件：STATE.md、AGENTS.md、PROGRESS.md</li><li>任务队列：tasks.json</li><li>Issue 跟踪系统：GitHub Issues、Linear</li><li>数据库：SQLite、PostgreSQL</li></ul><h2 id="成本与安全考量" tabindex="-1"><a class="header-anchor" href="#成本与安全考量" aria-hidden="true">#</a> 成本与安全考量</h2><p>Loop Engineering 虽然强大，但如果使用不当，可能会带来高昂的成本和安全风险。</p><p>很显然，Loop 可能会消耗大量的 API 额度。在中等规模代码库上运行 50 -100 次迭代可能花费 ¥500 - 1000，甚至更高。</p><p>所以我们需要设计一套可靠的成本管控策略，下面分享一下我研究下来的一下方法和经验：</p><ul><li>设置严格的迭代限制永远不要省略max-iterations（最大迭代数）</li><li>从小规模开始先在 10-20 次迭代上测试，观察行为后再逐步扩大</li><li>计算 ROI这里需要设计一套符合公司自身的成本管控标准，比如 ¥500 的循环节省 20 小时工作？值得。完成 30 分钟能做的任务？不值得</li><li>使用成本较低的模型比如对于简单任务使用 Sonnet 而不是 Opus</li><li>监控和警报设置每日 API 使用警报，避免意外账单</li></ul>`,26))])}const b=i(p,[["render",c],["__file","03Loop.html.vue"]]);export{b as default};
